// Validate and extract all inputs from the webhook body
const body = $json.body || {};

const productUrl = body.product_url || "";
const questionSources = body.question_sources || ["product_page", "reviews", "competitors"];
const faqCount = Math.min(Math.max(parseInt(body.faq_count) || 20, 10), 30);
const tone = body.tone || "professional";
const language = body.language || "English";
const competitorComparison = body.competitor_comparison === true || body.competitor_comparison === "true";

if (!productUrl) {
  throw new Error("Missing required input: product_url");
}

return [
  {
    json: {
      product_url: productUrl,
      question_sources: questionSources,
      faq_count: faqCount,
      tone: tone,
      language: language,
      competitor_comparison: competitorComparison
    }
  }
];

const html = items[0].json.data || "";

// Remove scripts, styles, and all HTML tags
const cleanText = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/\s+/g, ' ')
  .trim();

// Pass through all inputs alongside the cleaned content
const inputs = items[0].json;

return [
  {
    json: {
      content: cleanText.slice(0, 10000),
      product_url: inputs.product_url,
      question_sources: inputs.question_sources,
      faq_count: inputs.faq_count,
      tone: inputs.tone,
      language: inputs.language,
      competitor_comparison: inputs.competitor_comparison
    }
  }
];

// Mine questions from multiple sources based on question_sources input
const item = items[0].json;
const sources = item.question_sources || ["product_page"];
const competitorComparison = item.competitor_comparison || false;

// Build question mining context
let miningContext = [];

if (sources.includes("product_page") || sources.includes("reviews")) {
  miningContext.push("Product page content and customer reviews");
}
if (sources.includes("competitors")) {
  miningContext.push("Competitor product comparisons");
}
if (sources.includes("amazon_qa")) {
  miningContext.push("Amazon Q&A style questions");
}
if (sources.includes("google_paa")) {
  miningContext.push("Google People Also Ask style questions");
}

// Always include all standard sources if none match
if (miningContext.length === 0) {
  miningContext = [
    "Product page content and customer reviews",
    "Amazon Q&A style questions",
    "Google People Also Ask style questions"
  ];
}

if (competitorComparison) {
  miningContext.push("Head-to-head competitor comparison questions");
}

return [
  {
    json: {
      ...item,
      mining_context: miningContext.join(", ")
    }
  }
];

let raw = $json.output || "";

// Strip any markdown code fences if present
raw = raw.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();

// Remove invalid placeholders
raw = raw.replace(/\(no answer provided\)/g, 'Please contact support for more information.');
raw = raw.replace(/N\/A/g, 'Please contact support for more information.');

// Extract JSON array
const start = raw.indexOf('[');
const end = raw.lastIndexOf(']');

let parsed = [];

try {
  if (start === -1 || end === -1) throw new Error("No JSON array found");
  const jsonString = raw.slice(start, end + 1);
  parsed = JSON.parse(jsonString);

  // Filter out any entries missing required fields
  parsed = parsed.filter(faq =>
    faq.question && faq.question.trim() !== '' &&
    faq.answer && faq.answer.trim() !== '' &&
    faq.theme && faq.theme.trim() !== ''
  );

  // Deduplicate by question
  const seen = new Set();
  parsed = parsed.filter(faq => {
    const key = faq.question.toLowerCase().trim();
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });

} catch (e) {
  return [{ json: { error: "Invalid AI JSON output", raw: raw.slice(0, 500) } }];
}

return [
  {
    json: {
      faqs: parsed,
      faq_count_requested: $('Question Mining Context').first().json.faq_count,
      faq_count_generated: parsed.length
    }
  }
];

const input = $json;

// Handle invalid AI output
if (!input.faqs || input.faqs.length === 0 || input.error) {
  return [
    {
      json: {
        success: false,
        faqs: [],
        json_ld: {},
        shopify_html: "",
        chatbot_csv: "",
        objection_faqs: [],
        themes: [],
        error: input.error || "AI returned no valid FAQs"
      }
    }
  ];
}

const faqs = input.faqs;
const safe = (val) => (val || "").replace(/"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const safeCsv = (val) => (val || "").replace(/"/g, '""');

// 1. JSON-LD schema markup (SEO rich snippets)
const jsonLd = {
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": faqs.map(faq => ({
    "@type": "Question",
    "name": faq.question,
    "acceptedAnswer": {
      "@type": "Answer",
      "text": faq.answer
    }
  }))
};

// 2. Shopify HTML (grouped by theme)
const byTheme = {};
faqs.forEach(faq => {
  const theme = faq.theme || "General";
  if (!byTheme[theme]) byTheme[theme] = [];
  byTheme[theme].push(faq);
});

let html = '<div class="faq-container">\n';
Object.entries(byTheme).forEach(([theme, items]) => {
  html += `  <div class="faq-theme">\n    <h2 class="faq-theme-title">${safe(theme)}</h2>\n`;
  items.forEach(faq => {
    html += `    <div class="faq-item">\n      <h3 class="faq-question">${safe(faq.question)}</h3>\n      <p class="faq-answer">${safe(faq.answer)}</p>\n    </div>\n`;
  });
  html += '  </div>\n';
});
html += '</div>';

// 3. Chatbot CSV (for chatbot training)
const csvRows = [
  "question,answer,theme",
  ...faqs.map(f => `"${safeCsv(f.question)}","${safeCsv(f.answer)}","${safeCsv(f.theme)}"`)
];
const csv = csvRows.join("\n");

// 4. Objection-handling subset
const objectionKeywords = ["price", "cost", "expensive", "return", "refund", "warranty", "guarantee", "availability", "delivery", "shipping", "competitor", "vs", "versus", "compare", "better", "difference"];
const objections = faqs.filter(f =>
  objectionKeywords.some(k =>
    (f.question || "").toLowerCase().includes(k) ||
    (f.theme || "").toLowerCase().includes(k)
  )
);

// 5. Theme summary
const themes = Object.keys(byTheme).map(theme => ({
  theme,
  count: byTheme[theme].length
}));

return [
  {
    json: {
      success: true,
      faq_count_requested: input.faq_count_requested,
      faq_count_generated: faqs.length,
      themes,
      faqs,
      json_ld: jsonLd,
      shopify_html: html,
      chatbot_csv: csv,
      objection_faqs: objections
    }
  }
];
